export interface Task {
  title: string;
  done: boolean;
  hours: number;
}

export interface ReportInput {
  title: string;
  tasks: Task[];
}

const MESSAGES = {
  doneLabel: "Done",
  openLabel: "Open",
  hoursLabel: "Hours",
  done: "done",
  total: "total",
};

interface RenderContext {
  readonly input: ReportInput;
  readonly separator: string;
  readonly bullet: string;
  readonly doneMarker: string;
  readonly openMarker: string;
}

const formatHours = (hours: number): string => `${hours}h`;

const renderHeader = (context: RenderContext): string[] => {
  const { title } = context.input;
  return [title, context.separator.repeat(title.length)];
};

const renderTasks = (context: RenderContext): string[] => {
  const lines: string[] = [];
  for (const task of context.input.tasks) {
    const marker = task.done ? context.doneMarker : context.openMarker;
    lines.push(
      `${context.bullet} ${marker} ${task.title} (${formatHours(task.hours)})`
    );
  }
  return lines;
};

const computeStats = (tasks: Task[]) => {
  let doneCount = 0;
  let totalHours = 0;
  for (const task of tasks) {
    if (task.done) doneCount += 1;
    totalHours += task.hours;
  }
  return { doneCount, totalHours };
};

const renderSummary = (context: RenderContext): string[] => {
  const { doneCount, totalHours } = computeStats(context.input.tasks);
  return [
    `${MESSAGES.doneLabel}: ${doneCount}`,
    `${MESSAGES.openLabel}: ${context.input.tasks.length - doneCount}`,
    `${MESSAGES.hoursLabel}: ${formatHours(totalHours)}`,
  ];
};

const renderFooter = (context: RenderContext): string[] => {
  const { doneCount, totalHours } = computeStats(context.input.tasks);
  const total = context.input.tasks.length;
  return [
    `${doneCount}/${total} ${MESSAGES.done}, ${formatHours(totalHours)} ${MESSAGES.total}`,
  ];
};

const RENDERERS: Record<string, (ctx: RenderContext) => string[]> = {
  header: renderHeader,
  tasks: renderTasks,
  summary: renderSummary,
  footer: renderFooter,
};

export interface ReportOptions {
  separator?: string;
  bullet?: string;
  sections?: string[];
  theme?: string;
  locale?: string;
  outputFormat?: "text";
}

export function formatReport(input: ReportInput, options?: ReportOptions): string {
  if (options?.theme && options.theme !== "default") {
    throw new Error(`no theme registered under: ${options.theme}`);
  }
  if (options?.locale && options.locale !== "en") {
    throw new Error(`no messages for locale: ${options.locale}`);
  }

  const context: RenderContext = {
    input,
    separator: options?.separator ?? "=",
    bullet: options?.bullet ?? "-",
    doneMarker: "[x]",
    openMarker: "[ ]",
  };

  const sections = options?.sections ?? ["header", "tasks", "footer"];
  const lines: string[] = [];
  for (const section of sections) {
    const renderer = RENDERERS[section];
    if (!renderer) {
      throw new Error(`no renderer for section: ${section}`);
    }
    lines.push(...renderer(context));
  }

  return lines.join("\n");
}

